int addInts(int x, int y) {
  return x + y;
}

double addDoubles(double x, double y) {
  return x + y;
}

int add(int x, int y) {
  return x + y;
}

double add(double x, double y) {
  return x + y;
}

int main() {
  cout << add(5, 5) << "\n";     // Calls the int version
  cout << add(5.5, 5.5); // Calls the double version
  return 0;
}
